-- AYAM GORENG BERLENGAS PADU
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'AYAM GORENG BERLENGAS PADU',
  'ayam-goreng-berlengas-padu',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/ayam-belengas.jpeg',
  'https://youtu.be/qsyxMcvjQDY?si=xTLhO7uYywwS9_0x',
  '[{"name":"Bahan Perap Ayam","amount":"","unit":"","isSection":true},{"name":"ayam (dipotong kecil)","amount":"500","unit":"g","isSection":false},{"name":"garam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk kunyit","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk kari","amount":"1","unit":"sudu besar","isSection":false},{"name":"perasa/ajinomoto (pilihan)","amount":"Sedikit","unit":"","isSection":false},{"name":"Bahan lain","amount":"","unit":"","isSection":true},{"name":"sos cili","amount":"2","unit":"sudu besar","isSection":false},{"name":"sos tiram","amount":"1","unit":"sudu besar","isSection":false},{"name":"kicap lemak manis","amount":"1","unit":"sudu besar","isSection":false},{"name":"gula (secukupnya)","amount":"1","unit":"sudu besar","isSection":false},{"name":"jus limau nipis","amount":"1","unit":"sudu besar","isSection":false},{"name":"bawang holland (hiris kasar)","amount":"1","unit":"biji","isSection":false},{"name":"kacang panjang (potong 2 inci panjang)","amount":"3","unit":"batang","isSection":false},{"name":"carrot (hiris halus/panjang)","amount":"½","unit":"batang","isSection":false},{"name":"cili padi (ikut citarasa)","amount":"5–8","unit":"biji","isSection":false},{"name":"Minyak","amount":"secukupnya","unit":"","isSection":false}]'::jsonb,
  '["Gaul ayam dengan semua bahan perap ayam. Ketepikan (perap) 5 minit.","Dalam kuali, panaskan minyak secukupnya. Masukkan ayam yang telah diperap.","Goreng sehingga sedikit garing.","Masukkan sos cili, sos tiram dan kicap lemak manis. Gaul sebati.","Masukkan gula dan perahkan limau nipis. Gaul sehingga gula larut dan aroma limau naik.","Masukkan bawang holland, carrot, kacang panjang dan cili padi. Tumis hingga naik bau dan bawang layu.","Biar kuah ‘belengas’ sedikit (tak terlalu basah, tak terlalu kering).","Rasa dan suaikan dengan citarasa. Tutup api.","Hidang panas-panas."]'::jsonb,
  NULL,
  '["Main","Ayam"]'::jsonb,
  false
);

-- FILLET O FISH BURGER
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'FILLET O FISH BURGER',
  'fillet-o-fish-burger',
  'Snack',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/fisn-n-chips.jpeg',
  'https://youtu.be/s2pB5XA1lAM?si=tX-LFZyx0r4lLaLq',
  '[{"name":"Bahan Ikan","amount":"","unit":"","isSection":true},{"name":"ikan fillet (sutchi, dory, cod atau tilapia tanpa tulang)","amount":"3","unit":"keping","isSection":false},{"name":"garam","amount":"Sedikit","unit":"","isSection":false},{"name":"serbuk lada hitam","amount":"Sedikit","unit":"","isSection":false},{"name":"perahan jus lemon (pilihan, untuk hilangkan bau hanyir)","amount":"Sedikit","unit":"","isSection":false},{"name":"Bahan Salutan Kering","amount":"","unit":"","isSection":true},{"name":"/2 cawan (60g) tepung gandum","amount":"1","unit":"","isSection":false},{"name":"/2 sudu kecil garam","amount":"1","unit":"","isSection":false},{"name":"/2 sudu kecil serbuk lada hitam","amount":"1","unit":"","isSection":false},{"name":"/2 sudu kecil paprika atau serbuk cili","amount":"1","unit":"","isSection":false},{"name":"/4 sudu kecil serbuk bawang putih (pilihan)","amount":"1","unit":"","isSection":false},{"name":"Bahan Salutan Basah","amount":"","unit":"","isSection":true},{"name":"/4 cawan (90g) tepung gandum","amount":"3","unit":"","isSection":false},{"name":"/4 cawan (30g) tepung jagung","amount":"1","unit":"","isSection":false},{"name":"baking powder","amount":"1","unit":"sudu kecil","isSection":false},{"name":"air 7Up / air soda sejuk (lebih kurang 1 cawan)","amount":"250","unit":"ml","isSection":false},{"name":"Bahan Lain","amount":"","unit":"","isSection":true},{"name":"roti burger (burger buns)","amount":"3","unit":"keping","isSection":false},{"name":"keju (cheddar atau keju burger)","amount":"1–2","unit":"keping","isSection":false},{"name":"mentega untuk sapuan","amount":"Sedikit","unit":"","isSection":false},{"name":"Daun salad (pilihan)","amount":"","unit":"","isSection":false},{"name":"Sos Tartar Homemade","amount":"","unit":"","isSection":true},{"name":"mayonis","amount":"4","unit":"sudu besar","isSection":false},{"name":"jus lemon","amount":"1","unit":"sudu kecil","isSection":false},{"name":"timun jeruk cincang halus (pickles/gherkin)","amount":"1","unit":"sudu kecil","isSection":false},{"name":"garam","amount":"Sedikit","unit":"","isSection":false},{"name":"lada hitam","amount":"Sedikit","unit":"","isSection":false}]'::jsonb,
  '["Keringkan ikan dengan kitchen towel. Perap ikan dengan garam, lada hitam dan jus lemon selama 10–15 minit.","Dalam mangkuk, satukan semua bahan salutan kering. Salut ikan dengan bahan salutan kering.","Dalam mangkuk lain, satukan tepung gandum, tepung jagung dan baking powder. Tuang perlahan-lahan air 7Up sambil kacau hingga adunan licin dan sederhana pekat.","Panaskan minyak hingga 170–180°C. Set api sederhana.","Celup ikan salut kering ke dalam batter (salutan basah) dan goreng hingga keemasan dan rangup selama 5–7 minit. Toskan.","Sapu sedikit mentega pada bahagian dalam roti burger dan bakar atas kuali hingga sedikit perang.","Sediakan sos tartar dengan mencampurkan mayonis, jus lemon, timun jeruk cincang, garam dan lada hitam. Kacau rata dan simpan dalam peti sejuk 10–15 minit sebelum digunakan.","Untuk susun burger: letak sos tartar di bahagian bawah roti, letakkan salad jika ada, ikan goreng rangup, lapiskan keju, tambah lagi sos tartar kemudian tutup dengan roti atas."]'::jsonb,
  NULL,
  '["Snack","Burger","Ikan"]'::jsonb,
  false
);

-- SAMBAL SOTONG CWC
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SAMBAL SOTONG CWC',
  'sambal-sotong-cwc',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/sambal-siting.jpeg',
  'https://youtu.be/Jbxq-wovvek?si=Vd2D5kBTgVVKIgP2',
  '[{"name":"Bahan Kisar","amount":"","unit":"","isSection":true},{"name":"bawang merah besar","amount":"3","unit":"biji","isSection":false},{"name":"bawang putih (jika suka)","amount":"2","unit":"ulas","isSection":false},{"name":"cili kering – rebus/rendam dulu, buang biji (ikut citarasa)","amount":"10–20","unit":"tangkai","isSection":false},{"name":"air untuk kisar","amount":"Sedikit","unit":"","isSection":false},{"name":"Bahan lain","amount":"","unit":"","isSection":true},{"name":"sotong – bersihkan","amount":"1","unit":"kg","isSection":false},{"name":"/2 cawan minyak masak (menumis)","amount":"1","unit":"","isSection":false},{"name":"air asam jawa (ikut citarasa)","amount":"1–2","unit":"sudu besar","isSection":false},{"name":"gula melaka/gula perang (ikut citarasa)","amount":"1","unit":"sudu besar","isSection":false},{"name":"kicap manis","amount":"1","unit":"sudu besar","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"bawang besar (hiris untuk menumis)","amount":"1","unit":"biji","isSection":false},{"name":"bawang besar (potong bulat untuk finishing)","amount":"1","unit":"biji","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false}]'::jsonb,
  '["Kisar semua bahan kisar sehingga halus dan ketepikan.","Bersihkan sotong dan potong ikut citarasa.","Dalam kuali, masukkan sotong tanpa minyak. Masak seketika sehingga air sotong keluar (2–3 minit). Toskan sotong dan simpan air sotong untuk sambal.","Dalam kuali yang sama, panaskan minyak dan tumiskan bawang besar hiris sehingga naik bau.","Masukkan semua bahan kisar. Tumis sehingga naik bau dan mula pecah minyak. Sepanjang proses ini boleh tambah air sedikit sebanyak 2 kali supaya sambal masak sempurna.","Bila sambal dah garing dan pecah minyak, warna sambal akan bertukar lebih gelap.","Masukkan air sotong, air asam jawa, gula, kicap manis dan garam. Gaul rata dan sesuaikan rasa. Tambah sedikit air jika kuah terlalu kering.","Sambung masak sehingga sambal nampak semakin garing.","Masukkan sotong dan gaulkan sehingga semua bahan sebati.","Masukkan bawang besar yang dipotong bulat. Kacau sehingga sebati dan reneh lebih kurang 1 minit.","Tutup api dan sedia untuk dihidang."]'::jsonb,
  NULL,
  '["Main","Sambal","Sotong"]'::jsonb,
  false
);

-- KOBIS MASAK LEMAK MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'KOBIS MASAK LEMAK MUDAH',
  'kobis-masak-lemak-mudah',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/lemak-kobis.jpeg',
  'https://youtu.be/Jbxq-wovvek?si=Vd2D5kBTgVVKIgP2',
  '[{"name":"/2 biji kobis (dipotong sederhana, jangan terlalu halus)","amount":"1","unit":"","isSection":false},{"name":"carrot (dihiris serong nipis – optional)","amount":"1","unit":"batang","isSection":false},{"name":"ikan bilis (rendam seketika, tumbuk)","amount":"Segenggam","unit":"","isSection":false},{"name":"bawang besar (dihiris)","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih (dihiris)","amount":"2","unit":"ulas","isSection":false},{"name":"cili merah atau cili hijau (dihiris)","amount":"2","unit":"biji","isSection":false},{"name":"kotak santan kecil / 1 cawan santan pekat","amount":"1","unit":"","isSection":false},{"name":"/2 cawan air atau secukupnya","amount":"1","unit":"","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"Gula","amount":"secukup rasa","unit":"","isSection":false}]'::jsonb,
  '["Dalam periuk, masukkan bawang besar, bawang putih, ikan bilis dan air.","Didihkan sekejap hingga bawang layu.","Masukkan kobis, carrot dan cili. Gaul rata dan biar lembut sedikit.","Tambahkan santan pekat, garam dan gula.","Kacau perlahan atas api kecil hingga kuah mendidih perlahan dan naik minyak sedikit.","Tutup api. Jangan biar mendidih kuat supaya santan tidak pecah."]'::jsonb,
  NULL,
  '["Main","Sayur","Lauk Pauk"]'::jsonb,
  false
);

-- SERAWA DURIAN SAMPOI
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SERAWA DURIAN SAMPOI',
  'serawa-durian-sampoi',
  'Dessert',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/serawa-durian-sampoi.jpeg',
  'https://youtu.be/EkyTM_5bHBg?si=lFZtm3IsSvsIaMdI',
  '[{"name":"durian (ikut banyak mana nak isi)","amount":"10–15","unit":"ulas","isSection":false},{"name":"kotak (200ml) santan","amount":"1","unit":"","isSection":false},{"name":"Air secukupnya (lebih kurang 1","amount":"1½","unit":"","isSection":false},{"name":"daun pandan (simpulkan)","amount":"2","unit":"helai","isSection":false},{"name":"besar gula Melaka (guna separuh dulu, tambah jika nak manis)","amount":"2","unit":"ketul","isSection":false},{"name":"garam (sesuaikan dengan citarasa)","amount":"1","unit":"sudu kecil","isSection":false},{"name":"gula putih","amount":"2","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Dalam kuali atau periuk, masukkan durian, santan, air, gula Melaka dan daun pandan.","Masak atas api sederhana sambil kacau perlahan.","Bila kuah semakin pekat, masukkan gula putih dan garam.","Adjust rasa ikut kemanisan yang disukai.","Bila kuah semakin pekat dan nampak creamy, tutup api.","Sedia dihidang, enak dimakan dengan pulut atau begitu sahaja."]'::jsonb,
  NULL,
  '["Dessert","Durian"]'::jsonb,
  false
);

-- PULUT KUKUS PALING MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'PULUT KUKUS PALING MUDAH',
  'pulut-kukus-paling-mudah',
  'Staple',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/pulut-kukus-paling-mudah.jpeg',
  'https://youtu.be/EkyTM_5bHBg?si=lFZtm3IsSvsIaMdI',
  '[{"name":"beras pulut","amount":"2","unit":"cawan","isSection":false},{"name":"beras pulut susu (jika mahu lebih lemak & lembut)","amount":"1–2","unit":"sudu besar","isSection":false},{"name":"daun pandan (disimpul)","amount":"1","unit":"helai","isSection":false},{"name":"santan kotak (1 sudu besar sebelum kukus, 1 sudu besar dimasukkan bersama air)","amount":"2","unit":"sudu besar","isSection":false},{"name":"minyak masak","amount":"1","unit":"sudu besar","isSection":false},{"name":"garam","amount":"Secubit","unit":"","isSection":false},{"name":"Air","amount":"secukupnya (paras 1cm di atas permukaan pulut)","unit":"","isSection":false}]'::jsonb,
  '["Cuci beras pulut sekejap saja, cukup untuk buang habuk dan kotoran. Jangan basuh banyak kali supaya tekstur pulut kekal berkilat. Toskan hingga tiada air menitik.","Panaskan kukusan dan sediakan loyang. Letakkan daun pandan di dalam loyang.","Masukkan pulut yang sudah ditos ke dalam loyang.","Tambahkan air sehingga paras lebih kurang 1cm di atas permukaan pulut.","Masukkan 1 sudu besar santan, 1 sudu besar minyak masak dan garam. Gaul rata perlahan.","Bila pengukus sudah berasap, kukus pulut selama 20–30 minit sehingga pulut betul-betul masak tanpa ada biji putih keras di tengah.","Selepas masak, gemburkan pulut dengan garfu ketika masih panas supaya pulut tidak padat dan biji pulut kekal elok sebiji-sebiji."]'::jsonb,
  NULL,
  '["Staple","Pulut"]'::jsonb,
  false
);

-- MINI DONUT EXPRESS (5 MINIT)
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'MINI DONUT EXPRESS (5 MINIT)',
  'mini-donut-express-5-minit',
  'Snack',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/easy-donut.jpeg',
  'https://youtu.be/DS-lpM9yGoQ?si=N45w72TCQzmKomN_',
  '[{"name":"tepung self-rising (± 1 cawan penuh ratakan)","amount":"140","unit":"g","isSection":false},{"name":"yogurt plain (± 6.5 oz + 1/2 sudu besar)","amount":"190","unit":"g","isSection":false},{"name":"Bahan Ganti","amount":"","unit":"","isSection":true},{"name":"Pengganti yogurt","amount":"112","unit":"g","isSection":false},{"name":"Pengganti tepung self-rising (pilih satu)","amount":"","unit":"","isSection":true},{"name":"Pilihan 1","amount":"140","unit":"g","isSection":false},{"name":"Pilihan 2","amount":"140","unit":"g","isSection":false}]'::jsonb,
  '["Dalam mangkuk, satukan tepung self-rising dan yogurt.","Gaul sehingga menjadi adunan yang lembik dan melekit.","Jangan tambah tepung tambahan. Masukkan adunan melekit ini ke dalam piping bag.","Panaskan minyak hingga sekitar 170°C.","Picit adunan terus ke dalam minyak panas dan goreng secara berperingkat sehingga keemasan.","Angkat dan toskan minyak.","Gaulkan donut dengan salutan atau glaze pilihan."]'::jsonb,
