  '["Snack","Donut","Pantas"]'::jsonb,
  false
);

-- THE BEST CHOC CHIPS COOKIES
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'THE BEST CHOC CHIPS COOKIES',
  'the-best-choc-chips-cookies',
  'Dessert',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/the-best-choc-chips-cookies.jpeg',
  'https://youtu.be/HB7gpdKDFvE?si=A9cro9UjxBLn-wVZ',
  '[{"name":"mentega tanpa garam (unsalted butter), dilembutkan","amount":"120","unit":"g","isSection":false},{"name":"gula kastor","amount":"50","unit":"g","isSection":false},{"name":"gula perang (light/dark brown sugar)","amount":"60","unit":"g","isSection":false},{"name":"esen vanila","amount":"1","unit":"sudu kecil","isSection":false},{"name":"telur (saiz M, ±50g)","amount":"1","unit":"biji","isSection":false},{"name":"tepung gandum (all-purpose flour)","amount":"150","unit":"g","isSection":false},{"name":"/2 sudu kecil baking soda","amount":"1","unit":"","isSection":false},{"name":"coklat gelap (dark chocolate), dicincang","amount":"50","unit":"g","isSection":false},{"name":"coklat cip","amount":"100","unit":"g","isSection":false}]'::jsonb,
  '["Panaskan oven pada suhu 190°C selama 10 minit. Api atas bawah, OFF kipas.","Pukul mentega seketika.","Masukkan gula kastor dan gula perang. Pukul hingga sebati dan sedikit kembang.","Masukkan esen vanila dan telur. Pukul sekejap hingga bercampur dan bertukar warna pucat.","Ayak tepung gandum dan baking soda, kemudian masukkan ke dalam adunan. Gaul rata menggunakan spatula.","Tambah coklat gelap cincang dan coklat cip. Gaul sekadar sebati.","Bentukkan doh menggunakan sudu atau scoop kecil dan letak atas loyang beralas baking paper.","Bakar pada suhu 190°C selama 12 minit atau hingga tepi cookies keperangan.","Sejukkan atas redai sebelum disimpan dalam bekas kedap udara."]'::jsonb,
  '["Tips:\n• Untuk cookies lebih chewy, jangan bakar terlalu lama.\n• Boleh simpan doh dalam peti sejuk selama 30 minit sebelum bakar untuk tekstur lebih padat.\n• Tambah sedikit garam (¼ sudu teh) jika suka rasa manis yang berimbang."]',
  '["Dessert","Cookies","Coklat"]'::jsonb,
  false
);

