  '[{"name":"Bahan Kisar/Tumbuk","amount":"","unit":"","isSection":true},{"name":"bawang putih","amount":"6","unit":"ulas","isSection":false},{"name":"bawang merah / 3 biji bawang besar","amount":"8","unit":"biji","isSection":false},{"name":"halia","amount":"3","unit":"inci","isSection":false},{"name":"Bahan Hiris","amount":"","unit":"","isSection":true},{"name":"halia","amount":"1","unit":"inci","isSection":false},{"name":"bawang merah","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih","amount":"2","unit":"ulas","isSection":false},{"name":"Bahan lain","amount":"","unit":"","isSection":true},{"name":"daging (potong melawan urat supaya cepat empuk)","amount":"1","unit":"kg","isSection":false},{"name":"kentang (potong & goreng hingga keperangan)","amount":"2","unit":"biji","isSection":false},{"name":"tomato (belah 4)","amount":"2","unit":"biji","isSection":false},{"name":"bawang besar (hiris bulat untuk akhir masakan)","amount":"1","unit":"biji","isSection":false},{"name":"cili hidup (belah & buang biji)","amount":"2–3","unit":"biji","isSection":false},{"name":"mangkuk minyak (untuk menumis dan menggoreng)","amount":"1","unit":"","isSection":false},{"name":"Serbuk kunyit & garam (untuk perap daging jika suka)","amount":"","unit":"","isSection":false},{"name":"cili kisar (boleh kurangkan ikut tahap pedas)","amount":"3","unit":"sudu besar","isSection":false},{"name":"sos tomato","amount":"6","unit":"sudu besar","isSection":false},{"name":"sos tiram","amount":"3","unit":"sudu besar","isSection":false},{"name":"Kicap manis secukupnya (anggaran 5","amount":"6","unit":"","isSection":false},{"name":"serbuk lada hitam","amount":"1","unit":"sudu besar","isSection":false},{"name":"/2 sudu kecil serbuk lada sulah","amount":"1","unit":"","isSection":false},{"name":"pes asam jawa","amount":"1","unit":"sudu besar","isSection":false},{"name":"air (untuk reneh daging)","amount":"Sedikit","unit":"","isSection":false},{"name":"Daun bawang untuk taburan (pilihan)","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Potong daging melintang urat supaya serat pendek dan cepat empuk.","Jika guna daging bahagian keras, rebus dulu 25–30 minit bersama 1 sudu kecil cuka hingga separuh lembut. Toskan dan simpan air rebusan untuk kuah.","Gaul daging dengan sedikit garam dan serbuk kunyit. Perap seketika jika suka.","Panaskan minyak dalam kuali. Goreng kentang hingga perang keemasan. Angkat dan toskan.","Jika suka, boleh goreng daging sekejap dalam minyak yang sama untuk aroma garing di tepi.","Gunakan minyak gorengan tadi (keluarkan sedikit jika terlalu banyak). Masukkan bahan hiris – halia, bawang merah dan bawang putih. Tumis hingga naik bau dan sedikit keperangan.","Masukkan bahan kisar. Tumis hingga wangi dan pecah minyak.","Masukkan serbuk lada hitam dan kacau rata.","Masukkan cili kisar. Tumis hingga pecah minyak.","Tambahkan sos tomato, sos tiram dan serbuk lada sulah. Gaul hingga sebati dan kuah menjadi pekat beraroma.","Masukkan daging rebus/goreng ke dalam tumisan.","Tuang sedikit air atau air rebusan daging untuk reneh.","Tambahkan kicap manis, pes asam jawa dan sedikit lagi air jika perlu.","Kacau rata, tutup kuali dan biarkan masak 15 minit atas api perlahan sehingga daging benar-benar lembut, berkilat dan kuah pekat.","Bila daging dah lembut, masukkan kentang goreng, tomato, cili hidup dan bawang besar hiris.","Kacau perlahan-lahan supaya bahan tidak hancur. Rasa dan sesuaikan dengan citarasa. Tambah garam jika perlu.","Bila bawang besar mula layu dan kuah nampak cantik berkilat, tutup api.","Biarkan lauk rehat 5–10 minit supaya minyak naik ke atas. Taburkan daun bawang sebelum hidang."]'::jsonb,
  '["Tip tambahan:\n• Jika suka rasa lebih manis & pekat, tambah sedikit lagi kicap manis di akhir masakan.\n• Untuk kuah lebih likat, buka tudung kuali dan masak dengan api sederhana selama 5 minit terakhir.\n• Guna daging batang pinang atau harimau menangis untuk hasil yang cepat empuk & juicy."]',
  '["Main","Daging","Kicap"]'::jsonb,
  false
);

-- KEK COKLAT PALING MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'KEK COKLAT PALING MUDAH',
  'kek-coklat-paling-mudah',
  'Dessert',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/kek-butter-tanpa-telur.jpeg',
  'https://youtu.be/kQrVTPoQ1fE?si=YJmzWo9oCVQjVviO',
  '[{"name":"Bahan Kering (diayak)","amount":"","unit":"","isSection":true},{"name":"tepung gandum (±190g)","amount":"1½","unit":"cawan","isSection":false},{"name":"gula pasir (±190–200g)","amount":"1","unit":"cawan","isSection":false},{"name":"/4 cawan serbuk koko tanpa gula (±25g)","amount":"1","unit":"","isSection":false},{"name":"soda bikarbonat","amount":"1","unit":"sudu kecil","isSection":false},{"name":"/2 sudu kecil garam","amount":"1","unit":"","isSection":false},{"name":"Bahan Cecair","amount":"","unit":"","isSection":true},{"name":"air sejuk (chiller) (240ml)","amount":"1","unit":"cawan","isSection":false},{"name":"minyak sayuran (minyak jagung / canola / avocado) (±85ml)","amount":"6","unit":"sudu besar","isSection":false},{"name":"jus lemon ATAU cuka putih","amount":"1","unit":"sudu besar","isSection":false},{"name":"esen vanila","amount":"1","unit":"sudu kecil","isSection":false}]'::jsonb,
  '["Panaskan oven pada suhu 175°C. Gris loyang 9 inci dengan minyak dan alas dasar dengan baking paper. Set api atas bawah, OFF kipas.","Ayak semua bahan kering (tepung, gula, koko, soda bikarbonat & garam) ke dalam satu mangkuk besar.","Dalam bekas lain, campurkan air, minyak, jus lemon/cuka dan esen vanila.","Tuangkan bahan cecair ke dalam bahan kering.","Kacau perlahan-lahan dengan whisk hingga adunan licin dan tiada ketulan (lebih kurang 15–20 saat). Jangan overmix.","Tuang adunan ke dalam loyang yang telah disediakan.","Bakar di rak tengah selama lebih kurang 30 minit atau hingga lidi yang dicucuk ke tengah kek keluar bersih.","Sejukkan sepenuhnya dalam loyang sebelum disapu topping, glaze atau tabur gula aising."]'::jsonb,
  '["Kek coklat ini tidak menggunakan telur dan mentega, sesuai untuk versi lebih ringkas dan ringan."]',
  '["Dessert","Kek","Coklat"]'::jsonb,
  false
);

-- COKLAT FROSTING PALING MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'COKLAT FROSTING PALING MUDAH',
  'coklat-frosting-paling-mudah',
  'Dessert',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/choc-chips.jpeg',
  NULL,
  '[{"name":"(±120g) gula aising","amount":"1","unit":"cawan","isSection":false},{"name":"(±30g) mentega lembut","amount":"2","unit":"sudu besar","isSection":false},{"name":"(±8g) serbuk koko tanpa gula","amount":"1","unit":"sudu besar","isSection":false},{"name":"/2 sudu kecil (2–3ml) esen vanila","amount":"1","unit":"","isSection":false},{"name":"± 3 sudu kecil (±15ml) susu segar / susu cair (ikut kepekatan)","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Masukkan gula aising, mentega, serbuk koko dan esen vanila dalam mangkuk.","Pukul dengan mixer kelajuan rendah hingga semua bercampur.","Masukkan susu sedikit demi sedikit sambil pukul perlahan sehingga mencapai kepekatan yang diingini.","Bila campuran sudah licin, pukul pada kelajuan tinggi 10–15 saat hingga adunan ringan dan gebu.","Sedia untuk disapu atas kek yang sudah sejuk."]'::jsonb,
  NULL,
  '["Dessert","Frosting","Coklat"]'::jsonb,
  false
);

-- SOUFFLÉ OMELETTE GEBU
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SOUFFLÉ OMELETTE GEBU',
  'souffle-omelette-gebu',
  'Breakfast',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/fluffy-omelette.jpeg',
  'https://youtu.be/kQrVTPoQ1fE?si=XNzUYeNTgRRIQ51r',
  '[{"name":"telur","amount":"2","unit":"biji","isSection":false},{"name":"Keju","amount":"secukupnya","unit":"","isSection":false},{"name":"herba cincang (contoh: daun parsli, daun bawang, atau basil)","amount":"1","unit":"sudu kecil","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"Serbuk lada hitam","amount":"secukup rasa","unit":"","isSection":false},{"name":"mentega (untuk masak omelette)","amount":"1","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Asingkan telur: Pecahkan telur dan asingkan kuning serta putih telur ke dalam dua mangkuk berbeza.","Pukul putih telur dengan hand mixer pada kelajuan sederhana tinggi hingga kental dan membentuk puncak lembut (stiff peaks).","Dengan mixer yang sama, pukul kuning telur hingga sedikit gebu dan sebati.","Ambil lebih kurang 1/4 hingga 1/2 cawan putih telur dan campurkan ke dalam kuning telur. Gaul hingga sebati.","Tuang semula campuran kuning ke dalam baki putih telur dan kaup balik perlahan-lahan hingga semuanya bercampur menjadi adunan kuning pucat yang gebu.","Cairkan mentega dalam kuali kecil non-stick atas api sederhana.","Tuang adunan telur dan ratakan supaya memenuhi seluruh permukaan kuali. Masak selama 1 minit tanpa penutup.","Taburkan keju, herba, garam dan lada hitam di atasnya. Gaul perlahan di bahagian atas sahaja (jangan kacau dasar kuali).","Tutup kuali dan masak lagi 2 minit hingga bahagian atas telur hampir masak sepenuhnya.","Alih perlahan ke pinggan dan semasa menggelongsorkan keluar, lipat separuh. Sedia dihidang."]'::jsonb,
  NULL,
  '["Breakfast","Telur"]'::jsonb,
  false
);

-- SIMPLE BAKED BEANS
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SIMPLE BAKED BEANS',
  'simple-baked-beans',
  'Breakfast',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/simple-baked-beans.jpeg',
  'https://youtu.be/kQrVTPoQ1fE?si=XNzUYeNTgRRIQ51r',
  '[{"name":"besar baked beans 425g","amount":"1","unit":"tin","isSection":false},{"name":"mentega atau minyak zaitun","amount":"2","unit":"sudu besar","isSection":false},{"name":"bawang putih (cincang halus)","amount":"2","unit":"ulas","isSection":false},{"name":"bawang besar (cincang halus)","amount":"1","unit":"biji","isSection":false},{"name":"sos tomato","amount":"2","unit":"sudu besar","isSection":false},{"name":"sos cili","amount":"2","unit":"sudu kecil","isSection":false},{"name":"sos tiram","amount":"2","unit":"sudu kecil","isSection":false},{"name":"gula perang atau madu","amount":"2","unit":"sudu kecil","isSection":false},{"name":"garam","amount":"Sedikit","unit":"","isSection":false},{"name":"lada hitam","amount":"Sedikit","unit":"","isSection":false},{"name":"serbuk paprika atau cili flakes (optional)","amount":"Sedikit","unit":"","isSection":false},{"name":"Daun parsley kering untuk tabur","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Cairkan mentega dalam kuali atau panaskan minyak zaitun.","Tumis bawang putih dan bawang besar hingga layu dan sedikit keperangan.","Masukkan baked beans terus dari tin.","Tambah sos tomato, sos cili, sos tiram, gula perang, garam, lada hitam dan paprika.","Kacau sebati dan biar reneh atas api kecil 5 minit sampai kuah sedikit pekat dan berkilat.","Rasa dan suaikan garam atau manis. Jika terlalu pekat, tambah sedikit air.","Tabur parsley sebelum hidang."]'::jsonb,
  NULL,
  '["Breakfast","Lauk Roti"]'::jsonb,
  false
);

-- BIHUN GORENG KICAP MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'BIHUN GORENG KICAP MUDAH',
  'bihun-goreng-kicap-mudah',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/bihun-goreng-kicap-mudah.jpeg',
  'https://youtu.be/X9QMvNztXgw?si=5701vfo3fWgR_fX0',
  '[{"name":"bihun (400g) – rendam dalam air biasa 15 minit dan toskan","amount":"1","unit":"bungkus","isSection":false},{"name":"isi ayam / daging / udang / sotong (ikut suka)","amount":"250–300","unit":"g","isSection":false},{"name":"Tauhu goreng (jika ada)","amount":"","unit":"","isSection":false},{"name":"½ cawan air","amount":"2–2","unit":"","isSection":false},{"name":"bawang putih (cincang halus)","amount":"6–8","unit":"ulas","isSection":false},{"name":"kicap lemak manis","amount":"6–8","unit":"sudu besar","isSection":false},{"name":"kicap lemak masin atau 2 sudu besar kicap cair","amount":"4","unit":"sudu besar","isSection":false},{"name":"kicap pekat","amount":"4","unit":"sudu besar","isSection":false},{"name":"lada hitam tumbuk kasar","amount":"2","unit":"sudu besar","isSection":false},{"name":"kiub pati ayam Adabi","amount":"1","unit":"","isSection":false},{"name":"Sayur","amount":"secukupnya (contoh: sawi & kobis)","unit":"","isSection":false},{"name":"Minyak masak untuk menumis","amount":"","unit":"","isSection":false},{"name":"Garam","amount":"secukup rasa (jika perlu)","unit":"","isSection":false}]'::jsonb,
  '["Panaskan minyak dalam kuali besar. Tumis bawang putih hingga naik bau.","Masukkan isi ayam/daging/udang/sotong. Goreng hingga separuh masak.","Tambah air (mulakan dengan separuh dahulu), lada hitam dan kiub pati ayam. Kacau hingga larut.","Masukkan semua jenis kicap dan biar kuah mendidih sekejap supaya rasa sebati.","Masukkan tauhu goreng jika guna.","Masukkan bihun yang sudah direndam dan ditos. Gaul rata supaya warna dan rasa sekata. Gaul perlahan-lahan supaya bihun tidak hancur.","Jika nampak kering sebelum bihun lembut, tambah baki air sedikit demi sedikit.","Akhir sekali masukkan sayur. Gaul sebentar hingga sayur layu dan bihun lembut.","Rasa dan tambah garam jika perlu.","Bila asap sudah keluar dari celah-celah bihun, itu tanda bihun sudah siap. Hidang panas, boleh makan dengan limau kasturi dan cili padi jika suka pedas."]'::jsonb,
  NULL,
  '["Main","Bihun","Goreng"]'::jsonb,
  false
);

-- LABU MASAK LEMAK PUTIH BERSAMA BAYAM
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'LABU MASAK LEMAK PUTIH BERSAMA BAYAM',
  'labu-masak-lemak-putih-bersama-bayam',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/lemak-labu.jpeg',
  'https://youtu.be/_ZkovVFYrOo?si=mQah3xn5z2nwraMu',
  '[{"name":"bawang besar (tumbuk)","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih (tumbuk)","amount":"3","unit":"ulas","isSection":false},{"name":"/2 sudu kecil lada hitam (jika suka)","amount":"1","unit":"","isSection":false},{"name":"ikan bilis (dibersihkan, tumbuk)","amount":"Segenggam","unit":"","isSection":false},{"name":"Bayam","amount":"secukupnya (asingkan batang dan daun)","unit":"","isSection":false},{"name":"/2 biji labu kuning (potong sederhana)","amount":"1","unit":"","isSection":false},{"name":"kotak santan kecil","amount":"1","unit":"","isSection":false},{"name":"air (atau secukupnya)","amount":"1","unit":"cawan","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"cili hidup merah (jika suka)","amount":"1","unit":"batang","isSection":false}]'::jsonb,
  '["Dalam periuk, masukkan air dan didihkan seketika.","Masukkan bawang besar, bawang putih dan ikan bilis yang telah ditumbuk. Masukkan lada hitam jika guna. Biarkan hingga naik bau.","Tambah labu dan rebus hingga labu lembut (lebih kurang 8–10 minit).","Bila labu hampir empuk, masukkan batang bayam.","Perlahankan api dan tuang santan. Kacau perlahan supaya santan tidak pecah.","Bila kuah mula mendidih, masukkan daun bayam dan cili hidup.","Gaul sebentar hingga daun bayam layu.","Tambahkan garam secukup rasa, kacau sekejap dan tutup api."]'::jsonb,
  NULL,
  '["Main","Sayur","Masak Lemak"]'::jsonb,
  false
);

-- SAMBAL TUMIS IKAN BILIS SEMPOI
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SAMBAL TUMIS IKAN BILIS SEMPOI',
  'sambal-tumis-ikan-bilis-sempoi',
  'Side',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/sambal-ikan-bilis.jpeg',
  'https://youtu.be/_ZkovVFYrOo?si=mQah3xn5z2nwraMu',
  '[{"name":"Bahan Kisar","amount":"","unit":"","isSection":true},{"name":"cili kering – rebus hingga lembut, toskan","amount":"1","unit":"genggam","isSection":false},{"name":"udang kering – rendam sekejap, toskan","amount":"1","unit":"sudu besar","isSection":false},{"name":"bawang besar (saiz sederhana)","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih (jika suka)","amount":"2","unit":"ulas","isSection":false},{"name":"Bahan Lain","amount":"","unit":"","isSection":true},{"name":"bawang besar – potong bulat","amount":"1","unit":"biji","isSection":false},{"name":"ikan bilis – goreng garing dan toskan","amount":"1","unit":"genggam","isSection":false},{"name":"Minyak masak","amount":"secukupnya (lebihkan sedikit supaya sambal naik minyak cantik)","unit":"","isSection":false},{"name":"asam keping ATAU air asam jawa secukupnya","amount":"1–2","unit":"keping","isSection":false},{"name":"Gula","amount":"secukupnya","unit":"","isSection":false},{"name":"Garam","amount":"secukupnya","unit":"","isSection":false},{"name":"gula melaka (jika ada) untuk rasa karamel","amount":"Sedikit","unit":"","isSection":false}]'::jsonb,
  '["Rendam atau rebus cili kering. Toskan dan kisar bersama udang kering, bawang besar dan bawang putih hingga halus.","Panaskan minyak dan goreng ikan bilis sehingga garing. Angkat dan toskan. Ketepikan.","Dalam minyak yang sama, tumis bahan kisar hingga garing dan pecah minyak.","Masukkan asam keping, garam dan gula (atau gula melaka).","Masak hingga sambal menjadi pekat dan naik minyak cantik. Rasa dan sesuaikan dengan citarasa.","Akhir sekali, masukkan bawang besar potong bulat dan ikan bilis goreng.","Gaul sekejap sahaja supaya bawang tidak terlalu lembik.","Sedia untuk dihidang bersama nasi panas, lempeng, ubi rebus atau nasi lemak."]'::jsonb,
  NULL,
  '["Side","Sambal","Ikan Bilis"]'::jsonb,
  false
);

-- IKAN SIAKAP MASAK ASAM JAWA SEMPOI
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'IKAN SIAKAP MASAK ASAM JAWA SEMPOI',
  'ikan-siakap-masak-asam-jawa-sempoi',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/ikan-siakap-masak-asam-jawa-sempoi.jpeg',
  'https://youtu.be/fIJ1G-f1ZSk?si=u86cCfSE7mqvvhz0',
  '[{"name":"ikan siakap (dibersihkan & dipotong)","amount":"1","unit":"ekor","isSection":false},{"name":"Serbuk kunyit (untuk lumur ikan)","amount":"","unit":"","isSection":false},{"name":"Garam","amount":"secukupnya","unit":"","isSection":false},{"name":"bawang putih (hiris)","amount":"3","unit":"ulas","isSection":false},{"name":"bawang besar (hiris)","amount":"1","unit":"biji","isSection":false},{"name":"halia (hiris)","amount":"1","unit":"inci","isSection":false},{"name":"cili padi (ketuk atau biar sebiji)","amount":"6","unit":"biji","isSection":false},{"name":"air asam jawa (secukup rasa)","amount":"1","unit":"cawan","isSection":false},{"name":"Perasa / garam / gula","amount":"secukupnya","unit":"","isSection":false},{"name":"tomato (jika suka)","amount":"1–2","unit":"biji","isSection":false},{"name":"minyak untuk menumis","amount":"Sedikit","unit":"","isSection":false}]'::jsonb,
  '["Lumur ikan dengan garam dan serbuk kunyit. Goreng sehingga garing. Angkat dan toskan minyak.","Dalam kuali yang sama, tinggalkan sedikit minyak. Tumis bawang merah, bawang putih dan halia hingga wangi.","Masukkan air asam jawa dan biar mendidih.","Masukkan semula ikan goreng dan cili padi.","Perasakan dengan garam, gula dan sedikit serbuk perasa jika suka. Rasa dan sesuaikan dengan citarasa.","Masukkan tomato jika guna dan reneh sekejap hingga kuah sedikit pekat dan sebati dengan ikan.","Siap untuk dihidang."]'::jsonb,
  NULL,
  '["Main","Ikan","Asam"]'::jsonb,
  false
);

-- TELUR DADAR BENDI SPECIAL
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'TELUR DADAR BENDI SPECIAL',
  'telur-dadar-bendi-special',
  'Side',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/telur-dadar-bendi-special.jpeg',
  'https://youtu.be/fIJ1G-f1ZSk?si=u86cCfSE7mqvvhz0',
  '[{"name":"telur","amount":"3","unit":"biji","isSection":false},{"name":"bendi (saiz sederhana)","amount":"6–8","unit":"batang","isSection":false},{"name":"cili hidup (potong serong)","amount":"1","unit":"tangkai","isSection":false},{"name":"Cili padi (untuk versi pedas, pilihan)","amount":"","unit":"","isSection":false},{"name":"bawang (potong kiub/hiris halus)","amount":"1","unit":"biji","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"tepung gandum (jika suka)","amount":"1","unit":"sudu besar","isSection":false},{"name":"minyak","amount":"Sedikit","unit":"","isSection":false},{"name":"Air","amount":"secukupnya (untuk merebus bendi)","unit":"","isSection":false}]'::jsonb,
  '["Dalam periuk atau kuali, didihkan air secukupnya.","Bila air sudah mendidih, rebuskan bendi lebih kurang 1 minit sahaja. Tutup periuk jika boleh.","Angkat dan toskan bendi. Sejukkan seketika.","Potong atau hiris bendi sederhana (tidak terlalu tebal atau terlalu nipis).","Dalam mangkuk, pecahkan telur dan pukul seperti buat telur dadar biasa.","Masukkan bendi, bawang dan cili yang telah disediakan. Jika suka, tambah tepung gandum.","Kacau sehingga sebati.","Panaskan sedikit minyak dalam kuali.","Set api paling perlahan dan masukkan semua bancuhan telur.","Tutup kuali selama 5 minit. Kemudian terbalikkan telur dan masak lagi selama 4 minit pada api paling perlahan.","Siap untuk dihidang dengan nasi panas."]'::jsonb,
  NULL,
  '["Side","Telur","Sayur"]'::jsonb,
  false
);

-- BAKWAN JAGUNG RANGUP
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'BAKWAN JAGUNG RANGUP',
  'bakwan-jagung-rangup',
  'Snack',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/bakwan-jagung-rangup.jpeg',
  'https://youtu.be/svBHCvJ7tIA?si=J-l9FleREVQfEQvU',
  '[{"name":"jagung manis (lebih kurang 3 tongkol besar), ambil biji sahaja","amount":"500","unit":"g","isSection":false},{"name":"tepung gandum","amount":"150","unit":"g","isSection":false},{"name":"tepung beras (±1 sudu besar penuh, boleh skip tapi bantu rangupkan)","amount":"20","unit":"g","isSection":false},{"name":"gula pasir","amount":"1","unit":"sudu kecil","isSection":false},{"name":"bawang besar – tumbuk halus","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih – tumbuk halus","amount":"3","unit":"ulas","isSection":false},{"name":"telur","amount":"1","unit":"biji","isSection":false},{"name":"daun bawang – hiris halus","amount":"2","unit":"batang","isSection":false},{"name":"/2 sudu kecil serbuk ketumbar","amount":"1","unit":"","isSection":false},{"name":"/2 sudu kecil serbuk lada putih atau hitam","amount":"1","unit":"","isSection":false},{"name":"/2 sudu besar serbuk stok ayam","amount":"1","unit":"","isSection":false},{"name":"garam (±1/8 sudu kecil, sebab serbuk stok dah masin)","amount":"Secubit","unit":"","isSection":false},{"name":"Air sejuk (lebih kurang 100ml, tambah sedikit demi sedikit sampai adunan pekat tapi masih boleh disudu)","amount":"","unit":"","isSection":false},{"name":"Minyak untuk menggoreng","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Jika guna jagung segar, hiris biji jagung dari tongkol. Jika guna jagung dalam tin, toskan airnya (lebih kurang 2 tin besar).","Dalam mangkuk besar, campurkan tepung gandum, tepung beras, gula, serbuk ketumbar, serbuk lada, serbuk stok ayam dan garam.","Masukkan bawang besar, bawang putih, daun bawang, telur dan jagung.","Gaul rata sambil tuang air sejuk sedikit demi sedikit sampai dapat adunan pekat (tidak terlalu cair tetapi boleh dijatuhkan dengan sudu).","Panaskan minyak banyak dalam kuali atas api sederhana.","Ambil satu sudu besar adunan dan jatuhkan perlahan-lahan ke dalam minyak panas. Leperkan sedikit jika mahu.","Goreng hingga keperangan dan rangup di kedua-dua belah, lebih kurang 7–10 minit setiap keping bergantung pada saiz dan suhu minyak. Balikkan sekali sahaja.","saat sebelum angkat, besarkan api dan balik-balikkan bakwan untuk rangup ekstra.","Angkat dan toskan. Biarkan sejuk sedikit sebelum dihidang."]'::jsonb,
  '["Tips rangup tahan 3–4 jam:\n• Lepas goreng, biar bakwan sejuk betul-betul sebelum disimpan.\n• Jangan tutup bekas rapat masa masih panas, nanti wap buat lembik.\n• Untuk jual atau hidang lama, boleh goreng 80% dulu dan goreng semula 1–2 minit sebelum hidang.\n• Boleh tambah 1 sudu kecil minyak panas ke dalam adunan sebelum goreng untuk kulit luar yang lebih rangup."]',
  '["Snack","Goreng","Jagung"]'::jsonb,
  false
);

-- SOS CILI HOMEMADE
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SOS CILI HOMEMADE',
  'sos-cili-homemade',
  'Condiment',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/sweet-chilli-sauce.jpeg',
  'https://youtu.be/svBHCvJ7tIA?si=J-l9FleREVQfEQvU',
  '[{"name":"cili hidup merah (tambah cili padi jika nak pedas)","amount":"5–6","unit":"batang","isSection":false},{"name":"/2 cawan air (125g)","amount":"1","unit":"","isSection":false},{"name":"/2 cawan gula putih (±100g)","amount":"1","unit":"","isSection":false},{"name":"/2 cawan cuka putih (±120g)","amount":"1","unit":"","isSection":false},{"name":"bawang putih (cincang halus / untuk dikisar)","amount":"5","unit":"ulas","isSection":false},{"name":"garam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"tepung jagung (bancuh dengan 2 sudu besar air)","amount":"1","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Potong kasar cili merah.","Masukkan cili, air dan bawang putih ke dalam pengisar.","Kisar hingga halus atau biarkan sedikit bertekstur jika suka.","Tuang bahan kisar ke dalam periuk.","Masukkan gula, cuka dan garam.","Masak atas api sederhana hingga mendidih.","Kecilkan api dan biar mereneh 5–7 minit sambil kacau selalu supaya gula larut dan rasa sebati. Rasa dan sesuaikan dengan citarasa.","Masukkan bancuhan tepung jagung perlahan-lahan sambil kacau.","Masak lagi 2–3 minit hingga sos jadi pekat dan berkilat.","Tutup api dan biarkan sos sejuk sepenuhnya.","Pindahkan ke dalam botol atau balang bersih bertutup dan simpan dalam peti sejuk."]'::jsonb,
  '["Tip tambahan:\n1. Untuk versi kurang pedas, buang biji cili.\n2. Boleh tambah sedikit madu selepas masak untuk rasa lebih sedap dan berkilat.\n3. Sedap dimakan dengan ayam goreng, cucur, nugget, atau keropok lekor.\n4. Boleh tahan dalam peti sejuk hingga 3 minggu."]',
  '["Condiment","Sos","Cili"]'::jsonb,
  false
);

-- IKAN MASAK HALIA MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'IKAN MASAK HALIA MUDAH',
  'ikan-masak-halia-mudah',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/ikan-masak-halia-mudah.jpeg',
  'https://youtu.be/RJEsskOfQDI?si=4Ce3Of4vuKPlweQS',
  '[{"name":"ikan jenahak/merah/tenggiri atau lain-lain ikan pilihan","amount":"4–6","unit":"keping","isSection":false},{"name":"halia muda (dihiris halus)","amount":"3","unit":"inci","isSection":false},{"name":"daun bawang (bahagian bawah dihiris)","amount":"Sedikit","unit":"","isSection":false},{"name":"cili kering (cuci & toskan, tak perlu rendam)","amount":"4–6","unit":"tangkai","isSection":false},{"name":"cuka","amount":"2","unit":"sudu besar","isSection":false},{"name":"sos tiram","amount":"1","unit":"sudu besar","isSection":false},{"name":"Serbuk lada sulah","amount":"secukupnya","unit":"","isSection":false},{"name":"Garam","amount":"secukupnya","unit":"","isSection":false},{"name":"Gula","amount":"secukupnya","unit":"","isSection":false},{"name":"Air","amount":"secukupnya","unit":"","isSection":false},{"name":"minyak bijan (jika suka)","amount":"Sedikit","unit":"","isSection":false},{"name":"Minyak untuk menumis","amount":"","unit":"","isSection":false},{"name":"tepung jagung (bancuh dengan sedikit air, jika mahu pekatkan kuah)","amount":"1","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Didihkan air secukupnya dalam periuk.","Masukkan separuh daripada hirisan halia ke dalam air mendidih.","Masukkan kepingan ikan dan rebus sehingga ikan 70% masak. Angkat dan toskan.","Panaskan sedikit minyak dalam kuali.","Tumis baki halia hingga naik bau dan sedikit garing.","Masukkan daun bawang (bahagian bawah yang keras) dan tumis hingga naik bau.","Masukkan cili kering yang telah digunting. Tumis sekejap hingga wangi.","Masukkan sedikit air mengikut kepekatan kuah yang diingini. Biar mendidih seketika, boleh tutup periuk seketika.","Perasakan kuah dengan sos tiram, serbuk lada sulah, cuka, garam dan gula secukup rasa.","Masukkan ikan yang telah direbus tadi.","Jika mahu kuah lebih pekat, tuang bancuhan tepung jagung dan kacau hingga kuah sedikit pekat.","Gaul perlahan supaya ikan tidak hancur.","Masukkan sedikit minyak bijan jika suka dan sesuaikan rasa.","Taburkan daun bawang sebelum hidang dan rehatkan seketika.","Sedia dihidang."]'::jsonb,
  '["Tips:\n1. Boleh tambah sedikit bawang besar hiris jika mahu rasa lebih manis.\n2. Ikan siakap juga sesuai untuk resipi ini."]',
  '["Main","Ikan","Halia"]'::jsonb,
  false
);

-- SAMBAL TERUNG BERLADO
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SAMBAL TERUNG BERLADO',
  'sambal-terung-berlado',
  'Side',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/terung-balado.jpeg',
  'https://youtu.be/RJEsskOfQDI?si=4Ce3Of4vuKPlweQS',
  '[{"name":"terung panjang","amount":"3","unit":"biji","isSection":false},{"name":"/2–1 cawan minyak masak (untuk goreng & tumis)","amount":"1","unit":"","isSection":false},{"name":"bawang merah kecil / 1 biji bawang besar","amount":"4","unit":"biji","isSection":false},{"name":"bawang putih","amount":"5","unit":"ulas","isSection":false},{"name":"cili merah besar","amount":"4","unit":"tangkai","isSection":false},{"name":"cili padi merah (ikut tahap kepedasan)","amount":"5–10","unit":"tangkai","isSection":false},{"name":"tomato","amount":"1","unit":"biji","isSection":false},{"name":"/2 inci belacan (bakar atau goreng sekejap)","amount":"1","unit":"","isSection":false},{"name":"garam (ikut rasa)","amount":"1–2","unit":"sudu kecil","isSection":false},{"name":"gula","amount":"1","unit":"sudu kecil","isSection":false},{"name":"serbuk perasa / seasoning","amount":"Sedikit","unit":"","isSection":false},{"name":"daun limau purut (buang tulang tengah, hiris halus)","amount":"3","unit":"helai","isSection":false},{"name":"ikan bilis (digoreng garing)","amount":"1","unit":"cawan","isSection":false}]'::jsonb,
  '["Potong terung panjang kepada 2 atau 3 bahagian, kemudian belah 4.","Goreng terung dalam minyak panas hingga separuh masak dan lembut sedikit. Angkat dan toskan.","Dalam minyak yang sama, goreng ikan bilis sehingga garing dan toskan. Ketepikan.","Potong kasar bawang merah, bawang putih, cili merah besar, cili padi dan tomato.","Dalam minyak panas, tumis semua bahan potong bersama belacan hingga lembut dan naik bau.","Angkat bahan tumis dan toskan minyak seketika.","Kisar (guna chopper) semua bahan tumis tadi secara kasar atau gesek atas cobek. Jangan terlalu halus.","Dalam minyak gorengan yang sama, tumis kembali pes sambal tadi sehingga kering.","Bila sambal nampak kering dan minyak mula pecah, masukkan garam, gula dan serbuk perasa.","Tambahkan daun limau purut dan kacau rata. Keringkan sambal jika mahu tahan lebih lama.","Masukkan terung goreng dan gaul perlahan hingga sambal rata menyelaputi terung.","Angkat dan taburkan ikan bilis goreng sebelum dihidang."]'::jsonb,
  NULL,
  '["Side","Terung","Sambal"]'::jsonb,
  false
);

-- SUP TELUR PALING SIMPLE
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SUP TELUR PALING SIMPLE',
  'sup-telur-paling-simple',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/sup-telur-paling-simple.jpeg',
  'https://youtu.be/RJEsskOfQDI?si=7-W_xD9bwiwxwCbz',
  '[{"name":"telur","amount":"5","unit":"biji","isSection":false},{"name":"Fucuk (rendam hingga lembut, potong kasar)","amount":"","unit":"","isSection":false},{"name":"Suhun (rendam dan toskan)","amount":"","unit":"","isSection":false},{"name":"bawang merah / 1 biji bawang besar (tumbuk halus)","amount":"4","unit":"biji","isSection":false},{"name":"bawang putih (tumbuk halus)","amount":"3","unit":"ulas","isSection":false},{"name":"halia (tumbuk halus)","amount":"1","unit":"inci","isSection":false},{"name":"ikan bilis (dibersihkan, rendam dan tumbuk halus)","amount":"Segenggam","unit":"","isSection":false},{"name":"kentang (potong dadu sederhana)","amount":"2","unit":"biji","isSection":false},{"name":"lada hitam (ditumbuk kasar)","amount":"1","unit":"sudu teh","isSection":false},{"name":"Sedikit perahan lemon atau asam keping","amount":"secukupnya (ikut citarasa)","unit":"","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"Gula","amount":"secukup rasa","unit":"","isSection":false},{"name":"minyak","amount":"Sedikit","unit":"","isSection":false},{"name":"Air masak","amount":"secukupnya (lebih kurang 1.5 liter)","unit":"","isSection":false}]'::jsonb,
  '["Panaskan sedikit minyak dalam periuk.","Tumis bawang merah, bawang putih, halia dan ikan bilis hingga naik bau dan kekuningan.","Masukkan lada hitam dan kacau sebati.","Tuang air masak dan biarkan mendidih.","Bila air mendidih, masukkan kentang dan rebus hingga empuk.","Kecilkan api. Pecahkan telur satu persatu terus ke dalam sup. Biar telur terapung dan masak hingga mengeras. Jangan kacau dahulu.","Selepas telur mengeras, masukkan fucuk dan suhun yang sudah direndam.","Kacau perlahan supaya telur tidak hancur.","Perasakan dengan garam, gula dan sedikit perahan lemon atau masukkan asam keping.","Rasa dan sesuaikan dengan citarasa.","Tutup api dan hidangkan panas-panas. Boleh tabur daun bawang atau bawang goreng jika suka."]'::jsonb,
  NULL,
  '["Main","Sup","Telur"]'::jsonb,
  false
);

-- UDANG MASAK SOS TIRAM
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'UDANG MASAK SOS TIRAM',
  'udang-masak-sos-tiram',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/udang-masak-sos-tiram.jpeg',
  'https://youtu.be/RJEsskOfQDI?si=7-W_xD9bwiwxwCbz',
  '[{"name":"udang","amount":"500","unit":"g","isSection":false},{"name":"serbuk kunyit","amount":"1","unit":"sudu kecil","isSection":false},{"name":"Garam","amount":"secukupnya","unit":"","isSection":false},{"name":"tepung jagung / tepung maizena","amount":"1","unit":"sudu kecil","isSection":false},{"name":"bawang putih (tumbuk halus)","amount":"4","unit":"ulas","isSection":false},{"name":"halia (tumbuk halus)","amount":"2","unit":"inci","isSection":false},{"name":"cili padi / cabe rawit (dititik, ikut tahap kepedasan)","amount":"5","unit":"tangkai","isSection":false},{"name":"cili hidup merah/hijau (dihiris serong)","amount":"1","unit":"tangkai","isSection":false},{"name":"cili kering (dipotong)","amount":"5","unit":"tangkai","isSection":false},{"name":"labu bawang holland (potong kasar)","amount":"1","unit":"","isSection":false},{"name":"sos tiram","amount":"3","unit":"sudu besar","isSection":false},{"name":"sos cili","amount":"1","unit":"sudu besar","isSection":false},{"name":"sos tomato","amount":"1","unit":"sudu besar","isSection":false},{"name":"Kicap manis","amount":"secukupnya","unit":"","isSection":false},{"name":"Minyak bijan","amount":"secukupnya (jika suka)","unit":"","isSection":false},{"name":"Minyak masak","amount":"secukupnya","unit":"","isSection":false}]'::jsonb,
  '["Gaulkan udang dengan serbuk kunyit, garam dan tepung jagung. Biarkan 5–10 minit.","Panaskan minyak dan goreng udang separuh masak. Jangan terlalu lama supaya udang tidak keras. Angkat dan toskan.","Keluarkan lebihan minyak, tinggalkan sedikit untuk menumis.","Tumis bawang putih dan halia hingga naik bau.","Masukkan cili kering, cili padi dan bawang holland. Tumis hingga sedikit layu.","Tambah sos tiram, sos cili, sos tomato, kicap manis dan sedikit minyak bijan. Gaul rata dan biar mendidih sekejap. Rasa dan sesuaikan perisa.","Masukkan semula udang yang telah digoreng. Gaul rata hingga udang bersalut dengan sos.","Angkat dan hidangkan panas-panas bersama nasi putih."]'::jsonb,
  NULL,
  '["Main","Udang","Sos Tiram"]'::jsonb,
  false
);

-- BEBOLA UBI KELEDEK MANIS MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'BEBOLA UBI KELEDEK MANIS MUDAH',
  'bebola-ubi-keledek-manis-mudah',
  'Snack',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/sweet-potato-ball.jpeg',
  'https://youtu.be/DPc5cKsbyF0?si=X2KrAWS8hR7xlON9',
  '[{"name":"ubi keledek (berat selepas dikupas)","amount":"200","unit":"g","isSection":false},{"name":"gula (ikut tahap kemanisan ubi)","amount":"2–3","unit":"sudu besar","isSection":false},{"name":"/4 sudu kecil garam","amount":"1","unit":"","isSection":false},{"name":"tepung ubi kayu (tapioca starch)","amount":"30","unit":"g","isSection":false},{"name":"tepung gandum","amount":"15","unit":"g","isSection":false},{"name":"/4 sudu kecil serbuk penaik (baking powder)","amount":"1","unit":"","isSection":false},{"name":"santan (ikut keperluan doh)","amount":"1–4","unit":"sudu besar","isSection":false},{"name":"Minyak untuk menggoreng","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Potong ubi keledek kepada ketulan sederhana.","Kukus hingga lembut sepenuhnya (15–20 minit). Elakkan merebus supaya ubi tidak terlalu berair.","Cucuk bahagian paling besar dengan garpu untuk pastikan lembut, kemudian pindahkan ubi ke pinggan dan lenyek hingga halus.","Dalam mangkuk, campurkan ubi yang telah dilecek dengan gula dan garam.","Masukkan tepung ubi kayu, tepung gandum dan serbuk penaik yang telah diayak.","Gaul sekejap dan lihat tahap kelembapan doh.","Jika masih ada tepung kering yang sukar bercampur, tambah 1 sudu besar santan pada satu masa, gaul sebati sebelum tambah lagi. Jangan lebih 4 sudu besar santan.","Doh yang betul ialah lembut, tidak melekat di tangan dan mudah dibentuk.","Ambil doh menggunakan sudu kecil penyukat yang penuh dan gentel menjadi bebola kecil. Ulang sehingga habis.","Panaskan minyak yang cukup untuk tenggelamkan bebola doh sepenuhnya.","Suhu minyak sekitar 160°C (minyak sederhana panas).","Masukkan bebola dan kacau segera supaya tidak melekat di dasar kuali.","Pada awalnya bebola akan tenggelam, kemudian akan terapung bila hampir masak.","Teruskan mengacau perlahan supaya masak sekata dan perang sekata.","Goreng selama kira-kira 5 minit penuh untuk dapatkan kulit rangup walaupun sudah keperangan awal.","Jika selepas 5 minit masih pucat, naikkan sedikit suhu minyak.","Angkat, toskan minyak dan letakkan di atas tisu dapur.","Tekap perlahan dengan tisu lain untuk serap minyak berlebihan, kemudian pindahkan ke rak penyejuk dan biar suam.","Paling sedap dimakan semasa masih panas atau suam."]'::jsonb,
  '["Donut ini tidak tahan lama, jadi goreng hanya jumlah yang mahu dimakan.\n• Boleh simpan baki doh dalam peti sejuk hingga 2 hari dan goreng bila perlu.\n• Ubi keledek oren (jewel yam) kurang sesuai kerana kandungan air yang tinggi."]',
  '["Snack","Ubi","Goreng"]'::jsonb,
  false
);

-- DAGING BAWANG PUTIH PATTANI
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'DAGING BAWANG PUTIH PATTANI',
  'daging-bawang-putih-pattani',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/daging-bawang-putih-pattani.jpeg',
  'https://youtu.be/T2g-bN9KoV4?si=jLyqxSXWbgnpbpiZ',
  '[{"name":"daging hiris (boleh ganti ayam / sotong / udang)","amount":"500","unit":"g","isSection":false},{"name":"labu bawang putih (±30 ulas kecil) – basuh dan tumbuk kasar","amount":"3","unit":"","isSection":false},{"name":"bawang besar – tumbuk","amount":"1","unit":"biji","isSection":false},{"name":"bawang putih – tumbuk","amount":"3","unit":"ulas","isSection":false},{"name":"halia – tumbuk","amount":"1","unit":"inci","isSection":false},{"name":"kunyit hidup – tumbuk","amount":"5","unit":"inci","isSection":false},{"name":"lada hitam – ditumbuk","amount":"8","unit":"biji","isSection":false},{"name":"cili kering – cuci dan tos (tak perlu rendam)","amount":"3","unit":"biji","isSection":false},{"name":"bawang holland / bawang merah besar – potong kasar","amount":"1","unit":"biji","isSection":false},{"name":"cili padi merah & hijau (ikut citarasa)","amount":"15","unit":"biji","isSection":false},{"name":"daun limau purut","amount":"2–3","unit":"helai","isSection":false},{"name":"gula","amount":"1","unit":"sudu besar","isSection":false},{"name":"garam (secukupnya)","amount":"1","unit":"sudu kecil","isSection":false},{"name":"limau nipis (pilihan, jika suka)","amount":"1","unit":"biji","isSection":false},{"name":"Minyak untuk menggoreng dan menumis","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Panaskan minyak dan masukkan 3 labu bawang putih tumbuk.","Goreng bawang putih hingga keemasan dan garing. Angkat, tos dan ketepikan untuk topping.","Menggunakan minyak yang sama, tumis bawang besar tumbuk dan bawang putih tumbuk hingga wangi.","Masukkan daging hiris.","Tambah lada hitam tumbuk dan garam secukupnya. Gaul rata. Air daging akan mula keluar.","Masukkan halia dan kunyit hidup tumbuk. Gaul rata hingga sebati.","Masukkan cili kering yang dipotong kasar dan sambung masak hingga air daging hampir kering dan daging empuk. Proses ini ambil sedikit masa.","Masukkan bawang holland / bawang merah besar hiris.","Masukkan cili padi merah dan hijau.","Masukkan daun limau purut dan 1 sudu besar gula. Gaul rata.","Rasa dan sesuaikan dengan citarasa.","Tutup api. Jika suka, perahkan 1 biji limau nipis dan gaul rata.","Pindahkan daging ke atas pinggan hidangan dan taburkan bawang putih goreng garing yang disediakan awal tadi.","Sedia dihidang bersama nasi putih atau pulut."]'::jsonb,
  '["Boleh tukar protein:\n• Ayam – potong nipis memanjang, masak lebih cepat.\n• Sotong – masukkan sotong di peringkat akhir, jangan masak terlalu lama.\n• Udang – masukkan last, masak 2–3 minit sahaja."]',
  '["Main","Daging","Pedas"]'::jsonb,
  false
);

-- BURGER SALMON MUDAH (PATTY)
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'BURGER SALMON MUDAH (PATTY)',
  'burger-salmon-mudah-patty',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/burger-salmon-mudah-patty.jpeg',
  'https://youtu.be/suVGYIWeFI8?si=c50FTM8Ii0FT2Dwc',
  '[{"name":"isi ikan salmon (tanpa kulit)","amount":"300","unit":"g","isSection":false},{"name":"shallot (bawang merah kecil), cincang halus","amount":"1–2","unit":"ulas","isSection":false},{"name":"mustard ATAU jus lemon ATAU yogurt","amount":"1","unit":"sudu kecil","isSection":false},{"name":"jus lemon","amount":"1","unit":"sudu kecil","isSection":false},{"name":"/8 sudu kecil madu","amount":"1","unit":"","isSection":false},{"name":"dill segar, cincang (atau herba lain yang ada)","amount":"1–2","unit":"sudu besar","isSection":false},{"name":"/4 cawan (±30g) breadcrumbs","amount":"1","unit":"","isSection":false},{"name":"Garam","amount":"secukupnya","unit":"","isSection":false},{"name":"Lada hitam","amount":"secukupnya","unit":"","isSection":false},{"name":"mentega (untuk memasak)","amount":"Sedikit","unit":"","isSection":false},{"name":"roti burger","amount":"2","unit":"","isSection":false},{"name":"Slaw (untuk topping, lihat resipi Slaw Mudah)","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Dalam mangkuk, satukan shallot cincang, dill, mustard, jus lemon, madu dan lada hitam.","Buang kulit salmon jika ada.","Potong kira-kira 2/3 bahagian salmon kepada kiub kecil dan masukkan ke dalam mangkuk bersama bahan lain (atau guna chopper/food processor, tetapi elak kisar terlalu halus).","Cincang halus baki 1/3 salmon hingga hampir menjadi pes dan masukkan ke dalam mangkuk.","Gaul semua bahan hingga sebati.","Tambah breadcrumbs sedikit demi sedikit sekadar cukup untuk membentuk patty (anggaran 1/4 cawan).","Bentuk 2 patty dan tabur garam di permukaan sebelum memasak.","Panaskan pan non-stick atas api sederhana-rendah dan cairkan mentega.","Bila mentega mula perang, masukkan patty salmon.","Masak sehingga bahagian bawah perang, lebih kurang 3 minit, kemudian terbalikkan.","Masak lagi kira-kira 3 minit di bahagian satu lagi. Tekan perlahan, jika terasa firm, patty sudah masak (total lebih kurang 6 minit).","Sedia untuk disusun dalam burger bersama slaw."]'::jsonb,
  NULL,
  '["Main","Ikan","Burger"]'::jsonb,
  false
);

