  'SLAW MUDAH',
  'slaw-mudah',
  'Side',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/burger-salmon.jpeg',
  'https://youtu.be/suVGYIWeFI8?si=c50FTM8Ii0FT2Dwc',
  '[{"name":"kubis putih, hiris halus","amount":"1","unit":"cawan","isSection":false},{"name":"/2 cawan kubis ungu, hiris halus","amount":"1","unit":"","isSection":false},{"name":"/2 batang carrot, sagat halus","amount":"1","unit":"","isSection":false},{"name":"bawang merah atau bawang besar, hiris nipis","amount":"1","unit":"sudu besar","isSection":false},{"name":"mayonis","amount":"2","unit":"sudu besar","isSection":false},{"name":"jus lemon","amount":"1","unit":"sudu kecil","isSection":false},{"name":"/2 sudu kecil madu atau gula","amount":"1","unit":"","isSection":false},{"name":"garam","amount":"Sedikit","unit":"","isSection":false},{"name":"lada hitam","amount":"Sedikit","unit":"","isSection":false},{"name":"dill segar (optional, sangat sesuai dengan salmon)","amount":"1","unit":"sudu kecil","isSection":false}]'::jsonb,
  '["Satukan kubis putih, kubis ungu, carrot dan bawang dalam satu mangkuk.","Dalam mangkuk lain, bancuh dressing dengan mencampurkan mayonis, jus lemon, madu/gula, garam, lada hitam dan dill jika guna.","Tuang dressing ke dalam mangkuk sayur dan gaul rata.","Simpan dalam peti sejuk 15–20 minit supaya tekstur sedikit lembut dan rasa lebih sebati.","Cedok dan letakkan di atas burger salmon atau hidang sebagai side."]'::jsonb,
  NULL,
  '["Side","Salad"]'::jsonb,
  false
);

-- NASI BRIYANI TELUR
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'NASI BRIYANI TELUR',
  'nasi-briyani-telur',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/nasi-briyani-telur.jpeg',
  'https://youtu.be/sQ8vJQbn8lI?si=IN6aFL6_XXg-r5Xw',
  '[{"name":"Bahan Utama","amount":"","unit":"","isSection":true},{"name":"beras basmathi (rendam 30 minit)","amount":"3","unit":"cawan","isSection":false},{"name":"½ cawan air","amount":"3–3","unit":"","isSection":false},{"name":"telur","amount":"10","unit":"biji","isSection":false},{"name":"Bahan Perasa / Rempah","amount":"","unit":"","isSection":true},{"name":"bawang besar atau 10 biji bawang merah","amount":"3","unit":"biji","isSection":false},{"name":"halia (diparut)","amount":"2","unit":"inci","isSection":false},{"name":"yoghurt","amount":"1","unit":"cawan","isSection":false},{"name":"tomato (potong dadu)","amount":"2","unit":"biji","isSection":false},{"name":"cili hijau","amount":"3","unit":"biji","isSection":false},{"name":"air ros (jika ada)","amount":"2","unit":"sudu besar","isSection":false},{"name":"minyak sapi","amount":"2","unit":"sudu besar","isSection":false},{"name":"/2 cawan minyak masak","amount":"1","unit":"","isSection":false},{"name":"daun bay","amount":"5","unit":"helai","isSection":false},{"name":"Rempah empat sekawan (1 kayu manis, 1 bunga lawang, 2 biji pelaga, 2 cengkih)","amount":"","unit":"","isSection":false},{"name":"jintan putih","amount":"2","unit":"sudu teh","isSection":false},{"name":"daun ketumbar","amount":"2","unit":"tangkai","isSection":false},{"name":"daun pudina","amount":"2","unit":"tangkai","isSection":false},{"name":"/2 sudu teh serbuk kunyit","amount":"1","unit":"","isSection":false},{"name":"serbuk cili","amount":"2","unit":"sudu teh","isSection":false},{"name":"serbuk ketumbar","amount":"2","unit":"sudu teh","isSection":false},{"name":"garam masala","amount":"1½","unit":"sudu teh","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"Bawang goreng","amount":"secukupnya (untuk dalam nasi dan hiasan)","unit":"","isSection":false}]'::jsonb,
  '["Rebus telur hingga masak, kupas kulit.","Kelar sedikit permukaan telur.","Salut telur dengan sedikit serbuk cili, serbuk kunyit dan garam.","Panaskan sedikit minyak dan goreng telur sekejap hingga berwarna cantik. Angkat dan ketepikan.","Hiris halus bawang merah untuk menumis.","Panaskan minyak masak dalam periuk besar.","Masukkan daun bay, rempah empat sekawan dan jintan putih. Tumis seketika hingga naik bau.","Masukkan bawang hiris dan halia parut. Tumis hingga wangi dan bawang sedikit perang.","Masukkan tomato dan sedikit garam. Kacau rata hingga tomato sedikit lembik.","Masukkan minyak sapi dan gaul hingga sebati.","Masukkan serbuk kunyit, serbuk cili, serbuk ketumbar, garam masala, garam secukup rasa dan air ros. Gaul rata.","Tambahkan yoghurt dan kacau hingga sebati menjadi kuah rempah pekat.","Masukkan beras basmathi yang sudah ditoskan dan kacau hingga beras tersalut dengan rempah.","Tambah 3–3½ cawan air dan masak hingga beras separuh masak dan air mula menyerap. Tunggu sehingga air mendidih dan hampir kering.","Letakkan telur rebus di atas permukaan beras.","Taburkan daun pudina, daun ketumbar dan bawang goreng.","Tutup periuk dan biarkan nasi masak sepenuhnya hingga kering (boleh guna mode ''rice cooker'' atau api kecil jika atas dapur).","Selepas masak, gemburkan nasi perlahan dan biarkan rehat dalam mode ''keep warm'' selama 10 minit sebelum dihidang."]'::jsonb,
  '["Sedap dihidang panas bersama raitar atau acar."]',
  '["Main","Nasi","Briyani","Telur"]'::jsonb,
  false
);

-- RAITAR MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'RAITAR MUDAH',
  'raitar-mudah',
  'Side',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/aritar.jpeg',
  'https://youtu.be/sQ8vJQbn8lI?si=IN6aFL6_XXg-r5Xw',
  '[{"name":"yoghurt asli (plain yogurt)","amount":"1","unit":"cawan","isSection":false},{"name":"/2 biji timun, diparut atau dicincang halus","amount":"1","unit":"","isSection":false},{"name":"tomato kecil, dicincang halus (optional)","amount":"1","unit":"biji","isSection":false},{"name":"/2 biji bawang kecil, dicincang halus (optional)","amount":"1","unit":"","isSection":false},{"name":"/2 sudu teh serbuk jintan putih (optional)","amount":"1","unit":"","isSection":false},{"name":"jus lemon","amount":"1–2","unit":"sudu besar","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"gula","amount":"Sedikit","unit":"","isSection":false},{"name":"daun ketumbar atau pudina untuk hiasan","amount":"Sedikit","unit":"","isSection":false}]'::jsonb,
  '["Campurkan yoghurt dengan timun dalam mangkuk.","Jika guna tomato dan bawang, masukkan sekali dan gaul rata.","Tambahkan perahan lemon, serbuk jintan putih (jika guna), garam dan sedikit gula.","Gaul hingga semua sebati.","Sejukkan dalam peti sejuk 15–30 minit sebelum dihidang.","Taburkan daun ketumbar atau pudina sebagai hiasan sebelum dihidang bersama nasi briyani atau lauk kari."]'::jsonb,
  NULL,
  '["Side","Yogurt","Accompaniment"]'::jsonb,
  false
);

-- CRÈME BRÛLÉE MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CRÈME BRÛLÉE MUDAH',
  'creme-brulee-mudah',
  'Dessert',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/crème-brûlée.jpeg',
  'https://youtu.be/7H199elMJjM?si=8zxoF4qhmAwEeBZj',
  '[{"name":"telur (gred A/B)","amount":"4","unit":"biji","isSection":false},{"name":"/2 cawan gula pasir","amount":"1","unit":"","isSection":false},{"name":"susu segar (500ml)","amount":"2","unit":"cawan","isSection":false},{"name":"esen vanilla","amount":"1","unit":"sudu kecil","isSection":false},{"name":"garam","amount":"Secubit","unit":"","isSection":false},{"name":"ramekin","amount":"4–6","unit":"","isSection":false},{"name":"gula pasir (untuk lapisan gula rangup)","amount":"2–3","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Dalam mangkuk, kacau telur dan esen vanilla sehingga sebati (jangan sampai berbuih kuat).","Dalam periuk, panaskan susu, gula dan garam atas api perlahan hingga hampir mendidih (naik asap sikit). Jangan biar mendidih. Tutup api.","Tuang sedikit demi sedikit susu panas ke dalam campuran telur sambil dikacau untuk elak telur masak mengejut.","Tapis custard ke dalam mangkuk lain supaya tekstur licin dan halus.","Tuang custard ke dalam ramekin. Boleh tapis sekali lagi ke dalam ramekin jika mahu lebih halus.","Susun ramekin dalam loyang pembakar dan tuang air panas ke dalam loyang sehingga menutupi separuh tinggi ramekin (water bath).","Bakar dalam oven yang telah dipanaskan pada 140–160°C di rak tengah selama 30–50 minit sehingga custard set tetapi bahagian tengah masih sedikit bergoyang.","Keluarkan ramekin, biarkan sejuk sepenuhnya pada suhu bilik.","Tutup permukaan setiap ramekin dengan cling wrap dan simpan dalam peti ais sekurang-kurangnya 3–4 jam atau semalaman.","Sebelum hidang, tabur 1–2 sudu besar gula di atas permukaan custard sejuk dan ratakan.","Gunakan torch untuk membakar gula sehingga cair dan keemasan. Gerakkan torch perlahan-lahan untuk lapisan gula yang sekata.","Biarkan 2–3 minit hingga gula mengeras rangup sebelum dihidang."]'::jsonb,
  '["Jika kukus:\n1. Tuang custard ke dalam ramekin dan tutup permukaan dengan aluminium foil.\n2. Kukus atas api sederhana-rendah 30–45 minit hingga custard set tetapi masih sedikit bergoyang di tengah.\n3. Sejukkan dan simpan dalam peti ais sebelum letak gula dan torch seperti biasa.\nTips:\n• Jangan torch custard, hanya lapisan gula di atas.\n• Guna gula kastor supaya mudah cair dan rangup."]',
  '["Dessert","Custard"]'::jsonb,
  false
);

-- NASI GORENG DAGING MUDAH
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'NASI GORENG DAGING MUDAH',
  'nasi-goreng-daging-mudah',
  'Main',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/nasi-goreng-daging-mudah.jpeg',
  'https://youtu.be/nVq_IpfOJcE?si=9gi7ja3NblYn8G78',
  '[{"name":"Daging yang telah digoreng (hiris nipis) – anggaran 100","amount":"150","unit":"g","isSection":false},{"name":"nasi (sebaiknya nasi sejuk semalam)","amount":"2–3","unit":"cawan","isSection":false},{"name":"cili merah","amount":"3","unit":"biji","isSection":false},{"name":"cili padi (ikut tahap kepedasan)","amount":"3–6","unit":"biji","isSection":false},{"name":"bawang merah","amount":"3","unit":"biji","isSection":false},{"name":"bawang putih","amount":"5","unit":"ulas","isSection":false},{"name":"ikan bilis (jika suka)","amount":"Segenggam","unit":"","isSection":false},{"name":"minyak","amount":"4","unit":"sudu besar","isSection":false},{"name":"Garam","amount":"secukup rasa","unit":"","isSection":false},{"name":"Sayur pilihan jika ada (contoh: sawi, carrot dadu)","amount":"","unit":"","isSection":false}]'::jsonb,
  '["Panaskan minyak dalam kuali.","Goreng daging yang telah dilumur dengan kunyit dan sedikit garam sehingga garing. Angkat dan toskan. Ketepikan.","Tumbuk atau kisar kasar cili merah, cili padi, bawang merah dan bawang putih hingga halus.","Tambahkan ikan bilis ke dalam lesung/pengisar dan tumbuk sekali supaya tidak terlalu hancur.","Dalam kuali yang sama, jika minyak berlebihan keluarkan sedikit.","Tumis bahan kisar/tumbuk hingga wangi dan cili masak sepenuhnya (minyak mula kelihatan merah).","Masukkan nasi sejuk ke dalam kuali.","Masukkan daging yang telah digoreng tadi.","Kacau rata supaya nasi dan daging bersalut dengan bahan tumisan. Masukkan sayur jika ada.","Tambah garam secukup rasa.","Kacau lagi sehingga semua bahan sebati dan nasi panas.","Rasa dan sesuaikan. Siap untuk dihidang, sedap dengan bawang goreng atau telur mata."]'::jsonb,
  NULL,
  '["Main","Nasi Goreng","Daging"]'::jsonb,
  false
);

-- CRISPY TOFU
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'CRISPY TOFU',
  'crispy-tofu',
  'Snack',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/CWC 14/image/tauhu-goreng.jpeg',
  'https://youtu.be/jELWMDSM8Sw?si=F7rBwljT0aR2F28P',
  '[{"name":"tofu firm/keras","amount":"5","unit":"keping","isSection":false},{"name":"daun bawang (bahagian putih sahaja), hiris","amount":"3","unit":"batang","isSection":false},{"name":"cili hidup merah/hijau (potong dadu)","amount":"2","unit":"batang","isSection":false},{"name":"bawang putih, cincang","amount":"2","unit":"ulas","isSection":false},{"name":"air mendidih","amount":"4","unit":"cawan","isSection":false},{"name":"garam","amount":"1","unit":"sudu kecil","isSection":false},{"name":"telur (pukul sehingga berbuih)","amount":"1","unit":"biji","isSection":false},{"name":"tepung jagung","amount":"6","unit":"sudu besar","isSection":false},{"name":"Minyak masak (untuk menggoreng deep-fry)","amount":"","unit":"","isSection":false},{"name":"Lada sulah","amount":"secukupnya","unit":"","isSection":false},{"name":"Garlic salt","amount":"secukupnya (jika ada)","unit":"","isSection":false},{"name":"minyak (untuk menumis; boleh guna semula minyak menggoreng)","amount":"2","unit":"sudu besar","isSection":false}]'::jsonb,
  '["Potong tauhu firm menjadi kiub mengikut saiz yang diingini.","Didihkan 4 cawan air dan masukkan 1 sudu kecil garam.","Masukkan tauhu ke dalam air mendidih dan rebus selama kira-kira 5 minit.","Angkat, toskan tauhu dan keringkan dengan tisu dapur.","Dalam mangkuk, pukul telur hingga sedikit berbuih.","Masukkan tauhu ke dalam telur dan gaul perlahan supaya bersalut.","Salut tauhu dengan tepung jagung hingga rata.","Panaskan minyak yang banyak hingga sangat panas (±180–200°C).","Masukkan tauhu perlahan-lahan ke dalam minyak panas. Jangan kacau awal-awal.","Goreng kira-kira 5 minit hingga keemasan dan rangup.","Angkat dan toskan minyak.","Dalam kuali lain, panaskan 2 sudu besar minyak (boleh guna minyak gorengan tadi).","Tumis bawang putih, cili hidup dan daun bawang hingga wangi.","Masukkan garlic salt dan lada putih/sulah secukup rasa.","Masukkan tauhu goreng dan gaul rata supaya bersalut dengan bahan tumis.","Hidang panas-panas untuk hasil terbaik."]'::jsonb,
  '["Kenapa perlu rebus tauhu:\n1. Memadatkan tekstur supaya tidak mudah hancur semasa digoreng.\n2. Mengurangkan bau hanyir kedelai.\n3. Memasak sebahagian bahagian dalam, jadi bila digoreng luar rangup dan dalam kekal lembut.\n4. Memudahkan salutan tepung melekat."]',
  '["Snack","Tauhu","Goreng"]'::jsonb,
  false
);

-- SOS KACANG PEDAS MANIS
INSERT INTO public.recipes
  (title, slug, category, volume, status, difficulty, base_servings, rating,
   image, video, ingredients, steps, notes, tags, is_featured)
VALUES (
  'SOS KACANG PEDAS MANIS',
  'sos-kacang-pedas-manis',
  'Condiment',
  'VOL 14',
  'published',
  'Easy',
  4,
  4.8,
  '/images/recipes/vol-14/sos-kacang-pedas-manis.jpeg',
