  '[{"name":"cili hidup","amount":"2","unit":"","isSection":false},{"name":"bawang putih besar","amount":"1","unit":"ulas","isSection":false},{"name":"air","amount":"3","unit":"sudu besar","isSection":false},{"name":"cuka putih","amount":"3","unit":"sudu besar","isSection":false},{"name":"air asam jawa (1 sudu besar pes asam jawa + sedikit air)","amount":"3","unit":"sudu besar","isSection":false},{"name":"gula pasir","amount":"3","unit":"sudu besar","isSection":false},{"name":"gula melaka, dicincang","amount":"3","unit":"sudu besar","isSection":false},{"name":"/4 sudu kecil garam","amount":"1","unit":"","isSection":false},{"name":"Serbuk cili panggang","amount":"secukup rasa","unit":"","isSection":false},{"name":"kacang panggang, dihancurkan kasar (tumbuk)","amount":"3–4","unit":"sudu besar","isSection":false},{"name":"daun ketumbar, dicincang halus","amount":"2","unit":"sudu besar","isSection":false}]'::jsonb,
